import numpy as np

def double_q_learning(
    num_states: int,
    num_actions: int,
    experiences: list,
    alpha: float,
    gamma: float,
    coin_flips: list
) -> tuple:
    # Initialize both Q-tables as zero matrices
    Q1 = [[0.0] * num_actions for _ in range(num_states)]
    Q2 = [[0.0] * num_actions for _ in range(num_states)]

    for (state, action, reward, next_state, done), flip in zip(experiences, coin_flips):
        if flip == 0:
            # Q1 selects best action, Q2 evaluates it
            if done:
                target = reward
            else:
                best_action = max(range(num_actions), key=lambda a: Q1[next_state][a])
                target = reward + gamma * Q2[next_state][best_action]
            Q1[state][action] += alpha * (target - Q1[state][action])
        else:
            # Q2 selects best action, Q1 evaluates it
            if done:
                target = reward
            else:
                best_action = max(range(num_actions), key=lambda a: Q2[next_state][a])
                target = reward + gamma * Q1[next_state][best_action]
            Q2[state][action] += alpha * (target - Q2[state][action])

    return (
        np.array(Q1, dtype=np.float64),
        np.array(Q2, dtype=np.float64)
    )

