import numpy as np

def double_q_learning(
    num_states: int,
    num_actions: int,
    experiences: list,
    alpha: float,
    gamma: float,
    coin_flips: list
) -> tuple:
    Q1 = np.zeros((num_states, num_actions), dtype=np.float64)
    Q2 = np.zeros((num_states, num_actions), dtype=np.float64)

    for (state, action, reward, next_state, done), flip in zip(experiences, coin_flips):
        if flip == 0:
            if done:
                target = reward
            else:
                # Q1 picks best action index; Q2 evaluates its value
                best_action = np.argmax(Q1[next_state])
                target = reward + gamma * Q2[next_state, best_action]
            Q1[state, action] += alpha * (target - Q1[state, action])
        else:
            if done:
                target = reward
            else:
                # Q2 picks best action index; Q1 evaluates its value
                best_action = np.argmax(Q2[next_state])
                target = reward + gamma * Q1[next_state, best_action]
            Q2[state, action] += alpha * (target - Q2[state, action])

    return Q1, Q2
